import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-song-edit',
  templateUrl: './song-edit.component.html',
  styleUrls: ['./song-edit.component.scss']
})
export class SongEditComponent implements OnInit {

  constructor(private sSongs: SongsService) { }

  ngOnInit(): void {
    this.song = new Song();
  }

  async updateSong(song: Song) {
    try {
      this.loading = true;
      let { data: Song, error } = await this.sSongs.updateSong(song)


      alert('Canción actualizada!')
    } catch (error: any) {
      alert(error.error_description || error.message)
    } finally {
      this.loading = false;
    }
  }

  async addSong() {
    try {
      this.loading = true;
      delete this.song.id;
      this.sSongs.createSong(this.song).then((res:any) => this.song = new Song(res))
    } catch (error: any) {
      alert(error.error_description || error.message)
    } finally {
      this.loading = false;
    }
  }
}
